import{_ as a,o as l,c as e,a2 as t}from"./chunks/framework.LN3EJxkW.js";const p=JSON.parse('{"title":"前端 Roadmap：从零基础到前端专家","description":"","frontmatter":{},"headers":[],"relativePath":"01-frontend/roadmap.md","filePath":"01-frontend/roadmap.md","lastUpdated":1784212366000}'),o={name:"01-frontend/roadmap.md"};function r(n,i,d,h,c,s){return l(),e("div",null,[...i[0]||(i[0]=[t('<h1 id="前端-roadmap-从零基础到前端专家" tabindex="-1">前端 Roadmap：从零基础到前端专家 <a class="header-anchor" href="#前端-roadmap-从零基础到前端专家" aria-label="Permalink to &quot;前端 Roadmap：从零基础到前端专家&quot;">​</a></h1><p>这是一条可以独立学习的前端路线。顺序是“计算机与 Web 入门 → 页面 → 编程 → 工程应用 → 浏览器原理 → 架构与平台”，每个阶段都同时包含知识、练习、项目和验收。</p><h2 id="能力阶梯" tabindex="-1">能力阶梯 <a class="header-anchor" href="#能力阶梯" aria-label="Permalink to &quot;能力阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>能力目标</th><th>代表产出</th></tr></thead><tbody><tr><td>入门</td><td>会使用开发环境，理解网页如何被访问</td><td>第一个可访问网页</td></tr><tr><td>初级</td><td>能独立还原页面并编写交互</td><td>多页面响应式网站</td></tr><tr><td>中级</td><td>能用框架和 TypeScript 构建完整应用</td><td>带 API、路由、状态和测试的应用</td></tr><tr><td>高级</td><td>能处理性能、架构、质量和复杂场景</td><td>中大型应用与性能报告</td></tr><tr><td>专家</td><td>能建设平台、工具和标准并影响团队</td><td>Design System、CLI、基础设施或专项产品</td></tr></tbody></table><hr><h2 id="阶段零-计算机与-web-入门" tabindex="-1">阶段零：计算机与 Web 入门 <a class="header-anchor" href="#阶段零-计算机与-web-入门" aria-label="Permalink to &quot;阶段零：计算机与 Web 入门&quot;">​</a></h2><h3 id="开发环境" tabindex="-1">开发环境 <a class="header-anchor" href="#开发环境" aria-label="Permalink to &quot;开发环境&quot;">​</a></h3><ul><li>[ ] 文件、目录、路径、扩展名、文本编码和压缩包。</li><li>[ ] VS Code 的文件、搜索、终端、插件和调试面板。</li><li>[ ] 命令行的 <code>cd</code>、<code>pwd</code>、<code>ls</code>、<code>mkdir</code>、<code>cp</code>、<code>mv</code> 和删除操作。</li><li>[ ] Git 的仓库、工作区、暂存区、提交、分支、合并和远端。</li><li>[ ] Node.js、包管理器、<code>package.json</code>、依赖和脚本。</li><li>[ ] 使用浏览器 DevTools 查看 Elements、Console、Network 和 Sources。</li></ul><h3 id="web-如何工作" tabindex="-1">Web 如何工作 <a class="header-anchor" href="#web-如何工作" aria-label="Permalink to &quot;Web 如何工作&quot;">​</a></h3><ul><li>[ ] 客户端、服务器、浏览器和搜索引擎的角色。</li><li>[ ] URL、域名、DNS、IP、端口、HTTP 请求与响应。</li><li>[ ] HTML、CSS、JavaScript 各自负责什么。</li><li>[ ] 静态网站、动态网站、前端、后端和 API 的区别。</li><li>[ ] 本地开发服务器、构建产物、部署和 HTTPS 的基本概念。</li></ul><p>必做：创建一个 Git 仓库，用纯文本写出第一个 HTML 页面，在本地服务器打开并部署到公开地址。</p><p>验收：能从输入 URL 开始，口述浏览器获取并显示页面的大致过程；能独立创建、运行、调试和提交一个网页。</p><hr><h2 id="阶段一-html-与内容结构" tabindex="-1">阶段一：HTML 与内容结构 <a class="header-anchor" href="#阶段一-html-与内容结构" aria-label="Permalink to &quot;阶段一：HTML 与内容结构&quot;">​</a></h2><h3 id="基础语法" tabindex="-1">基础语法 <a class="header-anchor" href="#基础语法" aria-label="Permalink to &quot;基础语法&quot;">​</a></h3><ul><li>[ ] 元素、属性、嵌套、注释、空元素和字符实体。</li><li>[ ] 标题、段落、列表、链接、图片、音视频和表格。</li><li>[ ] <code>head</code>、元数据、favicon、语言和页面标题。</li><li>[ ] 块级与行内内容的基本区别。</li></ul><h3 id="语义、表单与可访问性" tabindex="-1">语义、表单与可访问性 <a class="header-anchor" href="#语义、表单与可访问性" aria-label="Permalink to &quot;语义、表单与可访问性&quot;">​</a></h3><ul><li>[ ] <code>header</code>、<code>nav</code>、<code>main</code>、<code>article</code>、<code>section</code>、<code>aside</code>、<code>footer</code>。</li><li>[ ] 表单控件、按钮、原生校验、自动填充和提交行为。</li><li>[ ] <code>label</code>、<code>fieldset</code>、<code>legend</code>、错误提示与帮助文本。</li><li>[ ] 标题层级、替代文本、焦点顺序和键盘操作。</li><li>[ ] Dialog、Popover、Details 等原生交互元素。</li><li>[ ] 响应式图片、<code>picture</code>、<code>srcset</code> 和懒加载。</li><li>[ ] SEO、Open Graph 和结构化内容基础。</li><li>[ ] ARIA 的使用边界：优先使用正确的原生元素。</li></ul><p>必做：个人主页、文章详情页、数据表格和支持键盘操作及自动填充的注册流程。</p><p>验收：关闭 CSS 和 JavaScript 后内容仍然结构清楚；能使用键盘完成表单；HTML 校验无关键错误。</p><hr><h2 id="阶段二-css-与视觉实现" tabindex="-1">阶段二：CSS 与视觉实现 <a class="header-anchor" href="#阶段二-css-与视觉实现" aria-label="Permalink to &quot;阶段二：CSS 与视觉实现&quot;">​</a></h2><h3 id="基础与布局" tabindex="-1">基础与布局 <a class="header-anchor" href="#基础与布局" aria-label="Permalink to &quot;基础与布局&quot;">​</a></h3><ul><li>[ ] 选择器、声明、单位、颜色、背景、边框和字体。</li><li>[ ] Cascade、Specificity、Inheritance 和默认样式。</li><li>[ ] Box Model、Normal Flow、<code>display</code>、溢出和滚动。</li><li>[ ] Position、Containing Block、BFC 和 Stacking Context。</li><li>[ ] Flexbox、Grid、多列布局和常见居中方法。</li><li>[ ] 响应式设计、媒体查询、移动优先和断点选择。</li></ul><h3 id="系统化与现代-css" tabindex="-1">系统化与现代 CSS <a class="header-anchor" href="#系统化与现代-css" aria-label="Permalink to &quot;系统化与现代 CSS&quot;">​</a></h3><ul><li>[ ] Custom Properties、Design Token 和主题切换。</li><li>[ ] Cascade Layers、Container Queries、Logical Properties。</li><li>[ ] 深色模式、RTL、高对比度和打印样式。</li><li>[ ] Transition、Animation、Transform 和关键帧。</li><li>[ ] <code>prefers-reduced-motion</code> 与动效性能。</li><li>[ ] BEM、CSS Modules、CSS-in-JS、Utility CSS 的边界与取舍。</li></ul><p>必做：从设计稿还原三个不同布局；实现响应式营销页、Dashboard 和一组可复用基础组件样式。</p><p>验收：能解释元素尺寸、滚动、定位和 <code>z-index</code> 的来源；缩放和不同屏幕下不依赖大量临时覆盖；能建立一套 Token。</p><hr><h2 id="阶段三-javascript-编程基础到语言深入" tabindex="-1">阶段三：JavaScript 编程基础到语言深入 <a class="header-anchor" href="#阶段三-javascript-编程基础到语言深入" aria-label="Permalink to &quot;阶段三：JavaScript 编程基础到语言深入&quot;">​</a></h2><h3 id="编程基础" tabindex="-1">编程基础 <a class="header-anchor" href="#编程基础" aria-label="Permalink to &quot;编程基础&quot;">​</a></h3><ul><li>[ ] 值、变量、类型、运算符、表达式和类型转换。</li><li>[ ] 条件、循环、函数、参数、返回值和递归基础。</li><li>[ ] Array、Object、String、Map、Set 和 Date 的常用操作。</li><li>[ ] 解构、展开、模板字符串和可选链。</li><li>[ ] 模块、导入导出、错误与异常处理。</li><li>[ ] 使用伪代码拆解问题，使用断点和日志调试。</li></ul><h3 id="dom、事件与网络" tabindex="-1">DOM、事件与网络 <a class="header-anchor" href="#dom、事件与网络" aria-label="Permalink to &quot;DOM、事件与网络&quot;">​</a></h3><ul><li>[ ] DOM 树、查询、创建、更新、删除和样式操作。</li><li>[ ] Event、冒泡、捕获、委托、默认行为和自定义事件。</li><li>[ ] 表单状态、校验、URL 与 Web Storage。</li><li>[ ] JSON、Fetch、HTTP 方法、状态码和请求错误处理。</li><li>[ ] 同步、异步、Callback、Promise 和 <code>async/await</code>。</li></ul><h3 id="语言深入" tabindex="-1">语言深入 <a class="header-anchor" href="#语言深入" aria-label="Permalink to &quot;语言深入&quot;">​</a></h3><ul><li>[ ] Scope、Closure、Execution Context、Hoisting。</li><li>[ ] Prototype、原型链、Class、<code>this</code> 和对象模型。</li><li>[ ] Iterator、Generator、Proxy 和 Reflect。</li><li>[ ] Event Loop、Call Stack、Task 和 Microtask。</li><li>[ ] Promise 组合、Async Iterator、AbortController。</li><li>[ ] Streams、Structured Clone、Transferable Object。</li><li>[ ] GC、WeakMap、WeakSet 与常见内存泄漏。</li></ul><p>必做：Todo、天气应用、分页搜索、图片懒加载、EventEmitter、并发调度器、可取消重试请求器和 SSE 流解析器。</p><p>验收：不依赖框架完成一个调用真实 API 的小型单页应用；能画出异步代码的调用栈、任务队列和生命周期。</p><hr><h2 id="阶段四-typescript、框架与完整应用" tabindex="-1">阶段四：TypeScript、框架与完整应用 <a class="header-anchor" href="#阶段四-typescript、框架与完整应用" aria-label="Permalink to &quot;阶段四：TypeScript、框架与完整应用&quot;">​</a></h2><h3 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h3><ul><li>[ ] 基础类型、函数、对象、接口、类型别名和枚举的取舍。</li><li>[ ] Union、Intersection、Narrowing、Generic。</li><li>[ ] Conditional、Mapped、Template Literal Types。</li><li>[ ] Discriminated Union、Type Predicate、<code>infer</code>。</li><li>[ ] Declaration File、Module Resolution、Compiler Options 和 Project References。</li><li>[ ] Runtime Schema Validation；类型系统不能替代运行时校验。</li></ul><h3 id="框架基础" tabindex="-1">框架基础 <a class="header-anchor" href="#框架基础" aria-label="Permalink to &quot;框架基础&quot;">​</a></h3><ul><li>[ ] 组件、Props、State、事件、条件、列表和生命周期。</li><li>[ ] 响应式更新或渲染模型，理解框架如何把状态映射为 UI。</li><li>[ ] 路由、Layout、表单、请求、错误边界和懒加载。</li><li>[ ] 客户端状态、服务端状态、URL 状态和持久化状态。</li><li>[ ] SSR、SSG、CSR 和 Hydration 的入门概念。</li><li>[ ] 先掌握一种主流框架，再比较 React、Vue、Svelte 等方案。</li></ul><h3 id="应用工程基础" tabindex="-1">应用工程基础 <a class="header-anchor" href="#应用工程基础" aria-label="Permalink to &quot;应用工程基础&quot;">​</a></h3><ul><li>[ ] Vite 等开发与构建工具的基本配置。</li><li>[ ] ESLint、Formatter、类型检查和 Git Hooks。</li><li>[ ] Unit、Component 和 E2E 测试入门。</li><li>[ ] 环境变量、配置、构建、部署和错误监控。</li><li>[ ] 依赖选择、升级、锁文件和供应链基础。</li></ul><p>必做：使用 TypeScript 和一种主流框架实现一个包含登录、路由、表单、CRUD、请求状态、错误处理和测试的完整应用。</p><p>验收：能从空目录搭建并部署完整应用；公共 API 类型稳定，不滥用 <code>any</code> 和类型断言；核心流程有自动化测试。</p><hr><h2 id="阶段五-浏览器与运行时" tabindex="-1">阶段五：浏览器与运行时 <a class="header-anchor" href="#阶段五-浏览器与运行时" aria-label="Permalink to &quot;阶段五：浏览器与运行时&quot;">​</a></h2><h3 id="页面加载" tabindex="-1">页面加载 <a class="header-anchor" href="#页面加载" aria-label="Permalink to &quot;页面加载&quot;">​</a></h3><ul><li>[ ] DNS、TCP、TLS、HTTP。</li><li>[ ] HTML Parser、Preload Scanner。</li><li>[ ] CSS 和 Script 的阻塞行为。</li><li>[ ] preload、prefetch、preconnect。</li><li>[ ] HTTP Cache、Service Worker Cache。</li><li>[ ] Network 瀑布图分析。</li></ul><h3 id="渲染流水线" tabindex="-1">渲染流水线 <a class="header-anchor" href="#渲染流水线" aria-label="Permalink to &quot;渲染流水线&quot;">​</a></h3><ul><li>[ ] Style、Layout、Paint、Composite。</li><li>[ ] 主线程、合成线程、光栅化。</li><li>[ ] Long Task、Layout Thrashing。</li><li>[ ] <code>requestAnimationFrame</code> 和任务切片。</li><li>[ ] GPU 合成层的收益与成本。</li></ul><h3 id="内存" tabindex="-1">内存 <a class="header-anchor" href="#内存" aria-label="Permalink to &quot;内存&quot;">​</a></h3><ul><li>[ ] Heap Snapshot、Allocation Timeline。</li><li>[ ] Detached DOM、Retainer Path。</li><li>[ ] Listener、Timer、Worker、Blob URL 泄漏。</li><li>[ ] 无界缓存治理。</li></ul><p>必做：</p><ul><li>[ ] 制造并修复六类内存泄漏。</li><li>[ ] 制作一个故意很卡的页面。</li><li>[ ] 记录优化前后 CPU、FPS、Heap、Long Task、LCP、INP 和 CLS。</li></ul><p>验收：能区分网络慢、JS 慢、渲染慢和后端慢；所有结论都有 Profile 或指标证据。</p><hr><h2 id="阶段六-应用与组件架构" tabindex="-1">阶段六：应用与组件架构 <a class="header-anchor" href="#阶段六-应用与组件架构" aria-label="Permalink to &quot;阶段六：应用与组件架构&quot;">​</a></h2><h3 id="组件设计" tabindex="-1">组件设计 <a class="header-anchor" href="#组件设计" aria-label="Permalink to &quot;组件设计&quot;">​</a></h3><ul><li>[ ] 单一职责、Composition。</li><li>[ ] Controlled / Uncontrolled。</li><li>[ ] Headless、Compound Component。</li><li>[ ] State Machine、Context Boundary。</li><li>[ ] Dependency Inversion、API Stability。</li><li>[ ] 业务组件、通用组件、基础组件的边界。</li></ul><h3 id="状态设计" tabindex="-1">状态设计 <a class="header-anchor" href="#状态设计" aria-label="Permalink to &quot;状态设计&quot;">​</a></h3><ul><li>[ ] URL 状态。</li><li>[ ] Server State。</li><li>[ ] Form State。</li><li>[ ] Interaction State。</li><li>[ ] Global State。</li><li>[ ] Persistent State。</li><li>[ ] 状态所有权与单一数据源。</li></ul><h3 id="应用分层" tabindex="-1">应用分层 <a class="header-anchor" href="#应用分层" aria-label="Permalink to &quot;应用分层&quot;">​</a></h3><ul><li>[ ] 按业务领域组织模块。</li><li>[ ] 建立单向依赖规则。</li><li>[ ] 封装第三方基础设施。</li><li>[ ] 统一错误、请求、缓存和重试模型。</li><li>[ ] 使用 ADR 记录决策。</li><li>[ ] 建立循环依赖检查。</li></ul><p>必做：设计一个企业后台，输出架构图、模块依赖图、状态分类、权限模型、错误模型和测试策略。</p><p>验收：新功能能明确归属；替换请求库、状态库或 UI 库时，不需要重写全部业务。</p><hr><h2 id="阶段七-性能工程" tabindex="-1">阶段七：性能工程 <a class="header-anchor" href="#阶段七-性能工程" aria-label="Permalink to &quot;阶段七：性能工程&quot;">​</a></h2><h3 id="指标" tabindex="-1">指标 <a class="header-anchor" href="#指标" aria-label="Permalink to &quot;指标&quot;">​</a></h3><ul><li>[ ] TTFB、FCP、LCP、INP、CLS。</li><li>[ ] Long Task、FPS、JS Heap。</li><li>[ ] Bundle Size、请求数量、缓存命中率。</li><li>[ ] 实验室数据与真实用户数据。</li><li>[ ] 分位数与性能预算。</li></ul><h3 id="加载性能" tabindex="-1">加载性能 <a class="header-anchor" href="#加载性能" aria-label="Permalink to &quot;加载性能&quot;">​</a></h3><ul><li>[ ] 关键请求链。</li><li>[ ] 首屏 JavaScript。</li><li>[ ] 路由和组件拆包。</li><li>[ ] 图片、字体和资源优先级。</li><li>[ ] CDN 与缓存。</li><li>[ ] SSR、SSG、CSR、Streaming SSR。</li><li>[ ] Hydration 和第三方脚本。</li></ul><h3 id="运行时性能" tabindex="-1">运行时性能 <a class="header-anchor" href="#运行时性能" aria-label="Permalink to &quot;运行时性能&quot;">​</a></h3><ul><li>[ ] 长任务切片。</li><li>[ ] Worker。</li><li>[ ] 虚拟列表。</li><li>[ ] 无效渲染。</li><li>[ ] 高频输入调度。</li><li>[ ] Canvas 和图表更新。</li><li>[ ] 内存边界。</li></ul><p>必做：为一个真实项目建立基线、性能预算、优化报告、线上采集和 CI 回归检查。</p><p>验收：不使用“感觉快了”作为结论；能说明每项优化的收益、成本和适用范围。</p><hr><h2 id="阶段八-工程化与工具链" tabindex="-1">阶段八：工程化与工具链 <a class="header-anchor" href="#阶段八-工程化与工具链" aria-label="Permalink to &quot;阶段八：工程化与工具链&quot;">​</a></h2><p>学习笔记：<a href="./notes/08-tooling/01-frontend-toolchain-monorepo-cli">前端工具链、Monorepo 与团队 CLI</a></p><h3 id="构建与模块" tabindex="-1">构建与模块 <a class="header-anchor" href="#构建与模块" aria-label="Permalink to &quot;构建与模块&quot;">​</a></h3><ul><li>[x] ESM、CJS、Package Exports。</li><li>[x] Tree Shaking、Code Splitting、Chunk。</li><li>[x] Source Map、HMR。</li><li>[x] Bundler Plugin、AST、Compiler Pipeline。</li><li>[x] ESM/CJS/类型声明发布。</li></ul><h3 id="monorepo" tabindex="-1">Monorepo <a class="header-anchor" href="#monorepo" aria-label="Permalink to &quot;Monorepo&quot;">​</a></h3><ul><li>[x] Workspace、Package Boundary。</li><li>[x] Task Graph、Remote Cache。</li><li>[x] Incremental Build。</li><li>[x] Versioning、Changelog、Release。</li><li>[x] 跨包依赖约束。</li></ul><h3 id="cli-与自动化" tabindex="-1">CLI 与自动化 <a class="header-anchor" href="#cli-与自动化" aria-label="Permalink to &quot;CLI 与自动化&quot;">​</a></h3><ul><li>[x] 交互式和非交互式命令。</li><li>[x] 模板、Dry Run、回滚。</li><li>[x] Migration、Codemod。</li><li>[x] 日志等级、单元和集成测试。</li></ul><p>必做：</p><ul><li>[ ] 一个构建插件。</li><li>[ ] 一个 AST Codemod。</li><li>[ ] 一个团队 CLI。</li><li>[ ] 一套 Monorepo 依赖规则。</li><li>[ ] 一套自动发布流程。</li></ul><p>验收：从工具使用者变成工具建设者，并能量化工具对团队效率的提升。</p><hr><h2 id="阶段九-测试、安全与可观测性" tabindex="-1">阶段九：测试、安全与可观测性 <a class="header-anchor" href="#阶段九-测试、安全与可观测性" aria-label="Permalink to &quot;阶段九：测试、安全与可观测性&quot;">​</a></h2><p>学习笔记：<a href="./notes/09-quality-security-observability/01-frontend-quality-security-observability">前端测试、安全与可观测性闭环</a></p><h3 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to &quot;测试&quot;">​</a></h3><ul><li>[x] Unit、Integration、Component、E2E。</li><li>[x] Contract、Visual Regression。</li><li>[x] Accessibility、Performance Test。</li><li>[x] 测试加载、失败、重试、权限和边界。</li><li>[x] Bug 修复附带回归测试。</li></ul><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li>[x] XSS、CSRF、CSP、CORS。</li><li>[x] Cookie、SameSite、OAuth。</li><li>[x] Token Storage、Open Redirect、Clickjacking。</li><li>[x] 依赖风险、Source Map 暴露。</li><li>[x] 前端权限不等于后端鉴权。</li></ul><h3 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h3><ul><li>[x] Runtime Error、Promise Error、API Error。</li><li>[x] Release、Source Map、Web Vitals。</li><li>[x] User Action、Trace、Business Event。</li><li>[x] 错误聚合、采样、告警和版本关联。</li></ul><p>验收：线上问题可以回答谁、在哪、何时、哪个版本、执行了什么、影响多少用户以及是否由本次发布引入。</p><hr><h2 id="阶段十-专家专项" tabindex="-1">阶段十：专家专项 <a class="header-anchor" href="#阶段十-专家专项" aria-label="Permalink to &quot;阶段十：专家专项&quot;">​</a></h2><p>学习笔记：<a href="./notes/10-expert-specializations/01-expert-frontend-architecture-selection">专家前端专项的架构选择：平台、复杂交互、AI 与 Web Platform</a></p><p>选择一到两个长期深入：</p><h3 id="企业级前端平台" tabindex="-1">企业级前端平台 <a class="header-anchor" href="#企业级前端平台" aria-label="Permalink to &quot;企业级前端平台&quot;">​</a></h3><p>Design System、CLI、权限、国际化、埋点、监控、Feature Flag、发布平台。</p><h3 id="复杂交互工程" tabindex="-1">复杂交互工程 <a class="header-anchor" href="#复杂交互工程" aria-label="Permalink to &quot;复杂交互工程&quot;">​</a></h3><p>编辑器、Canvas、白板、PDF 标注、可视化、大表格、拖拽、Undo/Redo、协作。</p><h3 id="ai-native-frontend" tabindex="-1">AI Native Frontend <a class="header-anchor" href="#ai-native-frontend" aria-label="Permalink to &quot;AI Native Frontend&quot;">​</a></h3><p>Streaming、Citation、Artifact、Tool Call、Agent Task、Approval、Memory、长任务。</p><h3 id="web-platform" tabindex="-1">Web Platform <a class="header-anchor" href="#web-platform" aria-label="Permalink to &quot;Web Platform&quot;">​</a></h3><p>WebAssembly、WebGPU、Worker、PWA、WebRTC、浏览器扩展。</p><hr><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><h3 id="书籍" tabindex="-1">书籍 <a class="header-anchor" href="#书籍" aria-label="Permalink to &quot;书籍&quot;">​</a></h3><ul><li>You Don’t Know JS Yet</li><li>JavaScript 高级程序设计</li><li>CSS in Depth</li><li>High Performance Browser Networking</li><li>Web Performance in Action</li><li>A Philosophy of Software Design</li><li>Clean Architecture</li></ul><h3 id="网站" tabindex="-1">网站 <a class="header-anchor" href="#网站" aria-label="Permalink to &quot;网站&quot;">​</a></h3><ul><li>MDN</li><li>web.dev</li><li>Chrome Developers</li><li>V8 Blog</li><li>TypeScript Handbook</li><li>React 官方文档</li><li>Playwright</li><li>OWASP</li></ul><hr>',120)])])}const b=a(o,[["render",r]]);export{p as __pageData,b as default};
